import base64
import datetime
from xml.etree import ElementTree as ET

from django.conf import settings

from .exceptions import SamlValidationError

NS = {
    "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
    "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
}


def get_saml_config():
    return getattr(settings, "SAML_SP", {})


def decode_saml_response(encoded_response: str) -> str:
    try:
        raw = base64.b64decode(encoded_response)
        return raw.decode("utf-8")
    except Exception as exc:
        raise SamlValidationError("Invalid base64 SAMLResponse") from exc


def parse_xml(xml_text: str) -> ET.Element:
    try:
        return ET.fromstring(xml_text)
    except ET.ParseError as exc:
        raise SamlValidationError("Malformed XML in SAMLResponse") from exc


def _parse_saml_time(value: str):
    if not value:
        return None
    try:
        if value.endswith("Z"):
            value = value[:-1] + "+00:00"
        return datetime.datetime.fromisoformat(value)
    except Exception:
        return None


def _utcnow():
    return datetime.datetime.now(datetime.timezone.utc)


def validate_saml_structure(root: ET.Element):
    if root.tag != f"{{{NS['samlp']}}}Response":
        raise SamlValidationError("Root element must be samlp:Response")

    status_code = root.find("./samlp:Status/samlp:StatusCode", NS)
    if status_code is None:
        raise SamlValidationError("Missing SAML StatusCode")

    status_value = status_code.attrib.get("Value", "")
    if not status_value.endswith(":Success"):
        raise SamlValidationError(f"SAML response is not successful: {status_value}")

    assertion = root.find("./saml:Assertion", NS)
    if assertion is None:
        raise SamlValidationError("Missing saml:Assertion")

    subject = assertion.find("./saml:Subject", NS)
    if subject is None:
        raise SamlValidationError("Missing saml:Subject")

    nameid = subject.find("./saml:NameID", NS)
    if nameid is None or not (nameid.text or "").strip():
        raise SamlValidationError("Missing saml:NameID")

    conditions = assertion.find("./saml:Conditions", NS)
    if conditions is not None:
        skew = int(get_saml_config().get("ALLOWED_CLOCK_SKEW_SECONDS", 300))
        now = _utcnow()
        not_before = _parse_saml_time(conditions.attrib.get("NotBefore"))
        not_on_or_after = _parse_saml_time(conditions.attrib.get("NotOnOrAfter"))

        if not_before and now + datetime.timedelta(seconds=skew) < not_before:
            raise SamlValidationError("Assertion is not yet valid")
        if not_on_or_after and now >= (not_on_or_after + datetime.timedelta(seconds=skew)):
            raise SamlValidationError("Assertion has expired")


def extract_session_index(root: ET.Element):
    authn_statement = root.find("./saml:Assertion/saml:AuthnStatement", NS)
    if authn_statement is not None:
        return authn_statement.attrib.get("SessionIndex")
    return None


def extract_nameid(root: ET.Element):
    el = root.find("./saml:Assertion/saml:Subject/saml:NameID", NS)
    return (el.text or "").strip() if el is not None and el.text else None


def extract_attributes(root: ET.Element):
    attributes = {}
    for attr in root.findall(".//saml:Assertion/saml:AttributeStatement/saml:Attribute", NS):
        name = attr.attrib.get("Name")
        friendly_name = attr.attrib.get("FriendlyName")
        values = []
        for val in attr.findall("./saml:AttributeValue", NS):
            text = "".join(val.itertext()).strip()
            if text:
                values.append(text)
        if name:
            attributes[name] = values
        if friendly_name and friendly_name not in attributes:
            attributes[friendly_name] = values
    return attributes


def map_user_fields(nameid: str, attributes: dict):
    cfg = get_saml_config()
    attr_map = cfg.get("ATTRIBUTE_MAP", {})
    result = {
        "username": nameid,
        "email": "",
        "first_name": "",
        "last_name": "",
    }

    for field, candidates in attr_map.items():
        for candidate in candidates:
            values = attributes.get(candidate)
            if values:
                result[field] = values[0]
                break

    if not result.get("username"):
        result["username"] = nameid
    return result


