from django.conf import settings
from django.contrib.auth import get_user_model


def get_or_create_user_from_saml(nameid: str, attributes: dict, field_data: dict):
    User = get_user_model()
    create_unknown = getattr(settings, "SAML_SP", {}).get("CREATE_UNKNOWN_USERS", True)
    update_fields = getattr(settings, "SAML_SP", {}).get("UPDATE_USER_FIELDS", True)

    username = field_data.get("username") or nameid

    user = None
    username_field = getattr(User, "USERNAME_FIELD", "username")

    try:
        user = User.objects.get(**{username_field: username})
    except User.DoesNotExist:
        if not create_unknown:
            return None
        create_kwargs = {username_field: username}
        if hasattr(User, "email"):
            create_kwargs["email"] = field_data.get("email", "") or ""
        user = User.objects.create_user(**create_kwargs)

    changed = False
    for field in ("email", "first_name", "last_name"):
        if hasattr(user, field):
            new_value = field_data.get(field, "")
            if update_fields and new_value and getattr(user, field) != new_value:
                setattr(user, field, new_value)
                changed = True

    if not user.is_active:
        user.is_active = True
        changed = True

    if changed:
        user.save()

    return user


# saml_sp/views.py
from django.conf import settings
from django.contrib.auth import login
from django.http import HttpResponseBadRequest, JsonResponse
from django.views.decorators.csrf import csrf_exempt
from django.views.decorators.http import require_POST

from .auth import get_or_create_user_from_saml
from .exceptions import SamlValidationError
from .utils import (
    decode_saml_response,
    extract_attributes,
    extract_nameid,
    extract_session_index,
    map_user_fields,
    parse_xml,
    validate_saml_structure,
)


@csrf_exempt
@require_POST
def acs_view(request):
    saml_response = request.POST.get("SAMLResponse")
    if not saml_response:
        return HttpResponseBadRequest("Missing SAMLResponse")

    try:
        xml_text = decode_saml_response(saml_response)
        root = parse_xml(xml_text)
        validate_saml_structure(root)

        nameid = extract_nameid(root)
        if not nameid:
            raise SamlValidationError("Unable to determine NameID")

        attributes = extract_attributes(root)
        field_data = map_user_fields(nameid, attributes)

        user = get_or_create_user_from_saml(nameid, attributes, field_data)
        if user is None:
            return HttpResponseBadRequest("User is not allowed")

        login(request, user, backend=settings.AUTHENTICATION_BACKENDS[0])

        session_index = extract_session_index(root)
        session_key_name = getattr(settings, "SAML_SP", {}).get("SESSION_INDEX_KEY", "saml_session_index")
        request.session[session_key_name] = session_index
        request.session["saml_nameid"] = nameid
        request.session["saml_attributes"] = attributes

        return JsonResponse(
            {
                "authenticated": True,
                "username": getattr(user, user.USERNAME_FIELD),
                "nameid": nameid,
                "attributes": attributes,
            }
        )
    except SamlValidationError as exc:
        return HttpResponseBadRequest(str(exc))


